import moment from '@lark/moment-timezone-polyfill'
import { getLocalTimezone, supportLocales } from './core'
import { getLocalNow, getMomentByUnix } from './extend'
import { formatMoment, getGMTTimezone, __T, IFormatOption } from './format'
import platform from './platform'

type TimePreciseness = 'hour' | 'minute' | 'second'
type TimePrecisenessOptions = {
  preciseness?: TimePreciseness;
  isZeroMinute?: boolean;
}
type DatePreciseness = 'month' | 'day'
type DatePrecisenessOptions = {
  preciseness?: DatePreciseness;
}

type FormatLengthType = 'long' | 'short'

type Unix = number
type TimeCompatible = moment.Moment | Date | Unix

const defaultLocale = 'en-US'
const localeMap = supportLocales.reduce((acc, key) => ({
  ...acc,
  [key.substr(0, 2)]: key,
}), {})

/**
 * i18n
 */
function i18n (key: string, locale?: string) {
  const localeCode = (locale || moment.locale() || defaultLocale).replace(/(\w+)[-_](\w+)/, function (m, $1, $2) {
    return `${$1}-${$2.toUpperCase()}`
  })
  const i18ns = platform[localeCode] || platform[localeMap[localeCode]]
  if (!i18ns) return undefined
  return i18ns[key]
}
function i18nTpl (key: string, data?: {}, { locale, is12Hour }: Pick<IFormatOption, 'locale' | 'is12Hour'> = {}) {
  const localeString = i18n(key, locale)
  if (!localeString) return key
  return __T(localeString, data, is12Hour)
}

function defineFormatterByI18nKey (key: string) {
  return function (date: moment.Moment, option: IFormatOption = {}, context = {}) {
    return formatMoment(date, i18n(key, option.locale), context, option)
  }
}

function defineCombinerByI18nKey<T extends {}> (key: string) {
  return function (data: T, option: IFormatOption = {}) {
    return i18nTpl(key, data, option)
  }
}

function getMoment (date: TimeCompatible, { locale, timezone }: IFormatOption = {}): moment.Moment | null {
  if (!date) return null
  let targetMoment: moment.Moment
  if (date instanceof Date) {
    targetMoment = moment(date)
  } else if (typeof date === 'number') {
    targetMoment = moment(date * 1000)
  } else {
    targetMoment = date.clone()
  }
  if (timezone) targetMoment = targetMoment.tz(timezone)
  if (locale) targetMoment = targetMoment.locale(locale)
  return targetMoment
}

function compatibleMoment<R extends any, O extends IFormatOption> (fn: (date: moment.Moment, options?: O) => R) {
  return function (date: TimeCompatible, options?: O): R {
    if (typeof options === 'object' && options.timezone) {
      options = Object.assign({}, options, {
        displayTimezone: options.timezone,
      })
    }
    if (typeof options === 'object' && options.locale && !isSupportedLocale(options.locale)) {
      options = Object.assign({}, options, {
        locale: moment.locale() || defaultLocale,
      })
    }
    const time = getMoment(date, options)
    if (!time) return '' as any as R
    return fn(time, options)
  }
}

function compatibleMomentRange<R, O extends IFormatOption> (fn: (start: moment.Moment, end: moment.Moment, options?: O) => R) {
  return function (start: TimeCompatible, end: TimeCompatible, options?: O): R {
    if (typeof options === 'object' && options.timezone) {
      options = Object.assign({}, options, {
        displayTimezone: options.timezone,
      })
    }
    const startTime = getMoment(start, options)
    const endTime = getMoment(end, options)
    if (!startTime || !endTime) return '' as any as R
    return fn(startTime, endTime, options)
  }
}

/**
 * ========================= Util ===================
 */

export function isSupportedLocale (locale: string) {
  return Boolean(platform[locale] || platform[localeMap[locale]])
}


